import React from 'react';
import { Wallet, TrendingUp, TrendingDown } from 'lucide-react';

const Menu = () => {
  return (
    <div>
      <h1>Olá! Este é o seu Controle Financeiro</h1>
      <div style={{ display: 'flex', gap: '20px', marginTop: '20px' }}>
        <div style={cardStyle}>
          <Wallet color="green" />
          <h3>Saldo Atual</h3>
          <p>R$ 0,00</p>
        </div>
        <div style={cardStyle}>
          <TrendingDown color="red" />
          <h3>Despesas do Mês</h3>
          <p>R$ 0,00</p>
        </div>
      </div>
    </div>
  );
};

const cardStyle = {
  padding: '20px',
  border: '1px solid #ddd',
  borderRadius: '8px',
  width: '200px',
  textAlign: 'center'
};

export default Menu;
